'use strict';

var react = require('react');

// src/useEffectOnce/index.ts
function useEffectOnce(cb, deps) {
  const mountRef = react.useRef(false);
  react.useEffect(() => {
    let returnValue;
    if (mountRef.current === false) {
      returnValue = cb();
      mountRef.current = true;
    }
    return returnValue;
  }, [deps]);
}

exports.useEffectOnce = useEffectOnce;
